     1	//! command — 在 PowerShell 中执行命令
     2	//!
     3	//! stdout/stderr 按 token 数截断后保存完整输出到 session 专属的 console/ 目录，
     4	//! 模型可通过绝对路径读取完整文件。
     5	//!
     6	//! Windows 的 PowerShell 输出通常是系统活动代码页编码（如中文 GBK、日文 Shift_JIS），
     7	//! 而非 UTF-8。此模块会自动检测编码并转换为 UTF-8，确保模型正确接收含非 ASCII
     8	//! 字符的命令输出。
     9	
    10	use std::path::PathBuf;
    11	use std::process::Stdio;
    12	use std::time::{SystemTime, UNIX_EPOCH};
    13	
    14	use anyhow::{Context, Result};
    15	use serde_json::Value;
    16	
    17	use super::{truncate_head_tok, ToolDef, ToolOutcome};
    18	use silences_core::ToolLimits;
    19	
    20	/// 尝试将字节数据解码为 UTF-8。
    21	fn decode_to_utf8(bytes: &[u8]) -> String {
    22	    if let Ok(s) = String::from_utf8(bytes.to_vec()) {
    23	        return s;
    24	    }
    25	    const WINDOWS_CODEPAGES: &[&encoding_rs::Encoding] = &[
    26	        encoding_rs::GBK,
    27	        encoding_rs::SHIFT_JIS,
    28	        encoding_rs::EUC_KR,
    29	        encoding_rs::WINDOWS_1252,
    30	    ];
    31	    for encoding in WINDOWS_CODEPAGES {
    32	        if let Some(decoded) = encoding.decode_without_bom_handling_and_without_replacement(bytes) {
    33	            return decoded.into_owned();
    34	        }
    35	    }
    36	    String::from_utf8_lossy(bytes).to_string()
    37	}
    38	
    39	pub fn tool(console_dir: Option<PathBuf>, limits: ToolLimits) -> ToolDef {
    40	    ToolDef {
    41	        name: "command",
    42	        description:
    43	            "what: 在 PowerShell 中执行命令。\nwhy: 需要运行脚本、编译、测试等操作时使用。\nhow: 如删除请用 trash 代替。",
    44	        schema: serde_json::json!({
    45	            "type": "object",
    46	            "properties": {
    47	                "command": {
    48	                    "type": "string",
    49	                    "description": "要执行的 PowerShell 命令"
    50	                },
    51	                "work_dir": {
    52	                    "type": "string",
    53	                    "description": "工作目录的绝对路径（可选，默认项目根目录）"
    54	                }
    55	            },
    56	            "required": ["command"],
    57	            "additionalProperties": false
    58	        }),
    59	        handler: Box::new(move |args| {
    60	            let cd = console_dir.clone();
    61	            Box::pin(execute(args, cd, limits))
    62	        }),
    63	    }
    64	}
    65	
    66	async fn execute(args: Value, console_dir: Option<PathBuf>, limits: ToolLimits) -> Result<ToolOutcome> {
    67	    let command = args["command"].as_str().context("缺少 command 参数")?;
    68	    let work_dir = args["work_dir"].as_str().map(|s| s.to_string());
    69	
    70	    let output = tokio::process::Command::new("powershell")
    71	        .args(["-NoProfile", "-Command", command])
    72	        .stdin(Stdio::null())
    73	        .stdout(Stdio::piped())
    74	        .stderr(Stdio::piped())
    75	        .current_dir(work_dir.as_deref().unwrap_or("."))
    76	        .output()
    77	        .await
    78	        .context("执行命令失败")?;
    79	
    80	    let stdout = decode_to_utf8(&output.stdout);
    81	    let stderr = decode_to_utf8(&output.stderr);
    82	
    83	    let stdout_max = limits.command_stdout_max_tok;
    84	    let stderr_max = limits.command_stderr_max_tok;
    85	
    86	    let (summary_stdout, stdout_truncated) = truncate_head_tok(&stdout, stdout_max);
    87	    let summary_stdout = if stdout_truncated {
    88	        let path = save_console_file(&console_dir, command, "stdout", &stdout);
    89	        format!(
    90	            "{}...\n[stdout 仅显示前 {stdout_max} tok，完整内容 ({len}B) 已保存至 {path}]\n",
    91	            summary_stdout,
    92	            len = stdout.len(),
    93	        )
    94	    } else {
    95	        stdout.clone()
    96	    };
    97	
    98	    let (summary_stderr, stderr_truncated) = truncate_head_tok(&stderr, stderr_max);
    99	    let summary_stderr = if stderr_truncated {
   100	        let path = save_console_file(&console_dir, command, "stderr", &stderr);
   101	        format!(
   102	            "{}...\n[stderr 仅显示前 {stderr_max} tok，完整内容 ({len}B) 已保存至 {path}]\n",
   103	            summary_stderr,
   104	            len = stderr.len(),
   105	        )
   106	    } else {
   107	        stderr.clone()
   108	    };
   109	
   110	    let mut summary = format!("$ {}\n", command);
   111	    if !summary_stdout.is_empty() {
   112	        summary.push_str(&summary_stdout);
   113	    }
   114	    if !summary_stderr.is_empty() {
   115	        if !summary_stdout.is_empty() {
   116	            summary.push('\n');
   117	        }
   118	        summary.push_str(&format!("stderr:\n{}", summary_stderr));
   119	    }
   120	    if let Some(code) = output.status.code() {
   121	        summary.push_str(&format!("\n退出码: {}", code));
   122	    }
   123	
   124	    Ok(ToolOutcome {
   125	        summary,
   126	        inverse: None,
   127	        rollback: false,
   128	        approval_pending: None,
   129	        inject_messages: vec![],
   130	        defer_rollback: false,
   131	    })
   132	}
   133	
   134	fn timestamp() -> String {
   135	    let dur = SystemTime::now()
   136	        .duration_since(UNIX_EPOCH)
   137	        .unwrap_or_default();
   138	    let secs = dur.as_secs();
   139	    let millis = dur.subsec_millis();
   140	    format!("{}_{:03}", secs, millis)
   141	}
   142	
   143	/// 保存完整输出到 console/{ts}_{tag}_{stream}.out，返回绝对路径
   144	fn save_console_file(console_dir: &Option<PathBuf>, command: &str, stream: &str, content: &str) -> String {
