    20	/// 尝试将字节数据解码为 UTF-8。
    21	fn decode_to_utf8(bytes: &[u8]) -> String {
    22	    if let Ok(s) = String::from_utf8(bytes.to_vec()) {
    23	        return s;
    24	    }
    25	    const WINDOWS_CODEPAGES: &[&encoding_rs::Encoding] = &[
    26	        encoding_rs::GBK,
    27	        encoding_rs::SHIFT_JIS,
    28	        encoding_rs::EUC_KR,
    29	        encoding_rs::WINDOWS_1252,
    30	    ];
    31	    for encoding in WINDOWS_CODEPAGES {
    32	        if let Some(decoded) = encoding.decode_without_bom_handling_and_without_replacement(bytes) {
    33	            return decoded.into_owned();
    34	        }
    35	    }
    36	    String::from_utf8_lossy(bytes).to_string()
    37	}
