   124	    Ok(ToolOutcome {
   125	        summary,
   126	        inverse: None,
   127	        rollback: false,
   128	        approval_pending: None,
   129	        inject_messages: vec![],
   130	        defer_rollback: false,
   131	    })
   132	}
   133	
   134	fn timestamp() -> String {
   135	    let dur = SystemTime::now()
   136	        .duration_since(UNIX_EPOCH)
   137	        .unwrap_or_default();
   138	    let secs = dur.as_secs();
   139	    let millis = dur.subsec_millis();
   140	    format!("{}_{:03}", secs, millis)
   141	}
   142	
   143	/// 保存完整输出到 console/{ts}_{tag}_{stream}.out，返回绝对路径
   144	fn save_console_file(console_dir: &Option<PathBuf>, command: &str, stream: &str, content: &str) -> String {
   145	    let dir = match console_dir {
   146	        Some(d) => d.clone(),
   147	        None => return "（未保存，无会话目录）".into(),
   148	    };
   149	    let _ = std::fs::create_dir_all(&dir);
   150	    let ts = timestamp();
   151	    let tag: String = command
   152	        .chars()
   153	        .filter(|c| c.is_alphanumeric() || *c == '_' || *c == '-')
   154	        .take(40)
   155	        .collect();
   156	    let tag = if tag.is_empty() { "cmd".to_string() } else { tag };
   157	    let file_path = dir.join(format!("{}_{}_{}.out", ts, tag, stream));
   158	    let _ = std::fs::write(&file_path, content);
   159	    file_path.to_string_lossy().to_string()
   160	}

