    20	    ToolDef {
    21	        name: "write",
    22	        description:
    23	            "创建新文件或覆写已读过的文件。\nwhy: 需要生成新代码或修改已有文件时使用。\nhow: 覆写已存在文件前必须先 read 该文件。",
