    29	                    "description": "文件绝对路径"
    30	                },
    31	                "content": {
    32	                    "type": "string",
    33	                    "description": "文件内容"
    34	                }
    35	            },
    36	            "required": ["path", "content"],
    37	            "additionalProperties": false
    38	        }),
