    46	async fn execute(args: Value, read_tracker: Arc<Mutex<HashSet<String>>>) -> Result<ToolOutcome> {
    47	    let path = args["path"].as_str().context("缺少 path 参数")?;
    48	    let content = args["content"].as_str().context("缺少 content 参数")?;
    49	
    50	    // 记录覆写前的原文（用于逆操作恢复）
    51	    let original = if Path::new(path).exists() {
    52	        // — 覆写已存在文件：必须先在 read 注册表中 —
    53	        let mut tracker = read_tracker.lock().await;
    54	        let canonical = std::path::absolute(path)
    55	            .ok()
    56	            .map(|p| p.to_string_lossy().replace('\\', "/").to_string())
    57	            .unwrap_or_else(|| path.to_string());
    58	
    59	        if !tracker.remove(&canonical) {
    60	            anyhow::bail!(
    61	                "文件已存在但未读取过: {}\n请先使用 read 工具读取该文件，确认内容后再进行覆写。",
    62	                path
    63	            );
    64	        }
    65	        drop(tracker);
    66	        Some(fs::read_to_string(path).unwrap_or_default())
    67	    } else {
    68	        None
    69	    };
    70	
    71	    // 确保父目录存在
    72	    if let Some(parent) = Path::new(path).parent() {
    73	        fs::create_dir_all(parent).context("创建父目录失败")?;
    74	    }
    75	
    76	    fs::write(path, content).context("写入文件失败")?;
    77	
    78	    let line_count = content.lines().count();
    79	    let path_owned = path.to_string();
    80	    let original_for_inverse = original.clone();
    81	    Ok(ToolOutcome {
    82	        summary: format!("已写入 {} ({} 行)", path, line_count),
    83	        inverse: Some(InverseOp::new(
    84	            format!("write {}", path),
    85	            move || {
    86	                if let Some(ref orig) = original_for_inverse {
    87	                    // 撤销覆写：恢复原文
    88	                    std::fs::write(&path_owned, orig)?;
    89	                } else {
    90	                    // 撤销新建：删除文件
    91	                    if std::path::Path::new(&path_owned).exists() {
    92	                        std::fs::remove_file(&path_owned)?;
    93	                    }
    94	                }
    95	                Ok(format!("已恢复 {}", path_owned))
    96	            },
    97	        )),
    98	        rollback: false,
    99	
   100	        approval_pending: None,
   101	    inject_messages: vec![],
   102	    defer_rollback: false,
   103	    })
   104	}

