   117	fn leading_comment_lines(content: &str, max_lines: usize) -> Option<String> {
   118	    let comment_prefixes = ["//", "#", ";", "--", "(*"];
   119	    let mut comments = Vec::new();
   120	    let mut line_count = 0;
   121	
   122	    for line in content.lines().take(max_lines) {
   123	        let trimmed = line.trim();
   124	        if trimmed.is_empty() {
   125	            continue;
   126	        }
   127	        if comment_prefixes.iter().any(|p| trimmed.starts_with(p)) {
   128	            comments.push(trimmed);
   129	            line_count += 1;
   130	        } else {
   131	            break;
   132	        }
   133	    }
   134	
   135	    if comments.is_empty() {
   136	        None
   137	    } else {
   138	        let mut result = comments.join("\n");
   139	        if line_count >= max_lines {
   140	            result.push_str(&format!(
   141	                "\n[提示: 仅显示前 {max_lines} 行注释，文件可能还有更多注释内容]"
   142	            ));
   143	        }
   144	        Some(result)
   145	    }
   146	}

