    77	/// 递归搜索目录，匹配文件名。跳过无法读取的目录。
    78	fn search_dir(root: &str, dir: &str, re: &Regex, results: &mut Vec<String>) {
    79	    let entries = match fs::read_dir(dir) {
    80	        Ok(e) => e,
    81	        Err(_) => return, // 跳过权限不足的目录
    82	    };
    83	    for entry in entries {
    84	        let entry = match entry {
    85	            Ok(e) => e,
    86	            Err(_) => continue,
    87	        };
    88	        let path = entry.path();
    89	        let name = entry.file_name().to_string_lossy().to_string();
    90	
    91	        if path.is_dir() {
    92	            if !name.starts_with('.') && name != "node_modules" && name != "target" {
    93	                search_dir(root, &path.to_string_lossy(), re, results);
    94	            }
    95	        } else if re.is_match(&name) {
    96	            let rel = path.to_string_lossy().to_string();
    97	            let display = rel
    98	                .strip_prefix(root)
    99	                .and_then(|s| s.strip_prefix(std::path::MAIN_SEPARATOR))
   100	                .unwrap_or(&rel);
   101	            results.push(format!("  {}", display));
   102	        }
   103	    }
   104	}

