    47	async fn execute(args: Value) -> Result<ToolOutcome> {
    48	    let file = args["file"].as_str().context("缺少 file 参数")?;
    49	    let raw_pattern = args["pattern"].as_str().context("缺少 pattern 参数")?;
    50	    let replacement = args["replacement"].as_str().context("缺少 replacement 参数")?;
    51	    let target_line = args.get("line").and_then(Value::as_u64);
    52	
    53	    let re_pattern = expand_pattern(raw_pattern);
    54	    let re = Regex::new(&re_pattern).context("正则表达式无效")?;
    55	    let original = read_file_robust(file)?;
    56	
    57	    let is_mk = is_tabsensitive(file);
    58	    let content = if is_mk { original.clone() } else { normalize(&original) };
    59	    let warning = if is_mk { format!("\n{}", TABSENSITIVE_WARNING) } else { String::new() };
    60	
    61	    // 全文匹配（不按行拆分，支持跨行正则）
    62	    let mut matches_positions: Vec<(usize, usize)> = Vec::new(); // (byte_start, byte_end)
    63	    for m in re.find_iter(&content) {
    64	        let m = m.context("正则匹配错误")?;
    65	        matches_positions.push((m.start(), m.end()));
    66	    }
    67	
    68	    if matches_positions.is_empty() {
    69	        anyhow::bail!("未找到匹配 \"{}\"", raw_pattern);
    70	    }
    71	
    72	    // 构建行起始字节偏移表 → O(log n) 字节定位行号
    73	    let line_starts: Vec<usize> = std::iter::once(0)
    74	        .chain(content.match_indices('\n').map(|(i, _)| i + 1))
    75	        .collect();
    76	    let pos_to_line = |pos: usize| -> usize {
    77	        match line_starts.binary_search(&pos) {
    78	            Ok(i) => i + 1,   // 恰好是行首
    79	            Err(i) => i,       // 落在 i 号行内（1-based，因为 Err 返回插入位置）
    80	        }
    81	    };
    82	
    83	    // 选择匹配
    84	    let (abs_start, abs_end) = match target_line {
    85	        Some(tl) => {
    86	            let tl = tl as usize;
    87	            matches_positions.sort_by_key(|&(start, _)| {
    88	                (pos_to_line(start) as isize - tl as isize).abs()
    89	            });
    90	            matches_positions[0]
    91	        }
    92	        None => {
    93	            if matches_positions.len() > 1 {
    94	                anyhow::bail!(
    95	                    "匹配不唯一（{} 处），请指定 line 参数选择目标行",
    96	                    matches_positions.len()
    97	                );
    98	            }
    99	            matches_positions[0]
   100	        }
   101	    };
   102	
   103	    let match_line = pos_to_line(abs_start);
