   321	/// 截断字符串到前 max_tok 个 token。
   322	/// 使用 DeepSeek tokenizer 精确计数；回退字节估算（1 tok ≈ 4 字节）。
   323	/// 返回（截断后的字符串, 是否被截断）。
   324	pub(super) fn truncate_head_tok(content: &str, max_tok: usize) -> (String, bool) {
   325	    if let Some(tok) = get_tokenizer() {
   326	        if let Ok(enc) = tok.encode(content, true) {
   327	            if enc.len() <= max_tok {
   328	                return (content.to_owned(), false);
   329	            }
   330	            let offsets = enc.get_offsets();
   331	            let end = offsets[max_tok.saturating_sub(1)].1.min(content.len());
   332	            return (content[..end].to_owned(), true);
   333	        }
   334	    }
   335	    // 回退：字节估算
   336	    let max_bytes = max_tok * 4;
   337	    if content.len() <= max_bytes {
   338	        return (content.to_owned(), false);
   339	    }
   340	    let end = content.floor_char_boundary(max_bytes.min(content.len()));
   341	    (content[..end].to_owned(), true)
   342	}
