   149	                if exts.contains(&ext.to_lowercase()) {
   150	                    search_file(&path.to_string_lossy(), re, results, context_lines)?;
   151	                }
   152	            }
   153	        }
   154	    }
   155	    Ok(())
   156	}
   157	
   158	/// 搜索单个文件，如果匹配则 push (formatted_text, match_count) 到 results
   159	fn search_file(path: &str, re: &Regex, results: &mut Vec<(String, usize)>, context_lines: usize) -> Result<()> {
   160	    let content = match read_file_robust(path) {
   161	        Ok(c) => normalize(&c),
   162	        Err(_) => return Ok(()), // 二进制文件跳过
   163	    };
   164	
   165	    let lines: Vec<&str> = content.lines().collect();
   166	    let mut file_parts = Vec::new();
   167	    for (i, line) in lines.iter().enumerate() {
   168	        if re.is_match(line).unwrap_or(false) {
   169	            let start = i.saturating_sub(context_lines);
   170	            let end = (i + context_lines + 1).min(lines.len());
   171	            let mut ctx = Vec::new();
   172	            ctx.push(format!("{}  {}", i + 1, line));
   173	            for j in start..i {
   174	                ctx.push(format!("  {}  {}", j + 1, lines[j]));
   175	            }
   176	            for j in (i + 1)..end {
   177	                ctx.push(format!("  {}  {}", j + 1, lines[j]));
   178	            }
   179	            file_parts.push(ctx.join("\n"));
   180	        }
   181	    }
   182	    if !file_parts.is_empty() {
   183	        let count = file_parts.len();
   184	        results.push((format!("[{}]\n{}", path, file_parts.join("\n---\n")), count));
   185	    }
   186	    Ok(())
   187	}

