   255	/// 大文件自动截断预览。
   256	///
   257	/// 使用 DeepSeek tokenizer 精确计数；tokenizer 不可用时回退字节估算（1 tok ≈ 4 字节）。
   258	/// 用 tokenizer offset 信息在精确的字符边界截断，保留开头 `head_tok` + 结尾 `tail_tok`。
   259	///
   260	/// 返回（截断后的内容, 是否被截断）。
   261	pub fn auto_truncate(
   262	    content: &str,
   263	    threshold_tok: usize,
   264	    head_tok: usize,
   265	    tail_tok: usize,
   266	) -> (String, bool) {
   267	    // ── 用真实 tokenizer 精确计数 ──
   268	    if let Some(tok) = get_tokenizer() {
   269	        if let Ok(enc) = tok.encode(content, true) {
   270	            let total = enc.len();
   271	            if total <= threshold_tok || head_tok + tail_tok >= total {
   272	                return (content.to_owned(), false);
   273	            }
   274	
   275	            let head_tok = head_tok.min(total);
   276	            let tail_tok = tail_tok.min(total);
   277	
   278	            let offsets = enc.get_offsets();
   279	            let head_end = offsets[head_tok.saturating_sub(1)].1.min(content.len());
   280	            let tail_start = offsets[total - tail_tok].0;
   281	            let tail_start = tail_start.max(head_end).min(content.len());
   282	
   283	            let truncated = format!(
   284	                "{}…\n[截断：文件较大 (~{} tok)，仅显示开头 {} tok + 结尾 {} tok]\n…{}",
   285	                &content[..head_end],
   286	                total,
   287	                head_tok,
   288	                tail_tok,
   289	                &content[tail_start..]
   290	            );
   291	            return (truncated, true);
   292	        }
   293	    }
   294	
   295	    // ── 回退：字节估算 ──
   296	    let threshold = threshold_tok * 4;
   297	    let head = head_tok * 4;
   298	    let tail = tail_tok * 4;
   299	
   300	    if content.len() <= threshold {
   301	        return (content.to_owned(), false);
   302	    }
   303	
   304	    let head_end = content.floor_char_boundary(head.min(content.len()));
   305	    let tail_start = content
   306	        .floor_char_boundary(content.len().saturating_sub(tail))
   307	        .max(head_end);
   308	
   309	    let truncated = format!(
   310	        "{}…\n[截断：文件较大 (~{}B)，仅显示开头 ~{}tok + 结尾 ~{}tok]\n…{}",
   311	        &content[..head_end],
   312	        content.len(),
   313	        head_tok,
   314	        tail_tok,
   315	        &content[tail_start..]
   316	    );
   317	
   318	    (truncated, true)
   319	}
