   133	/// 展开 pattern 中的反引号转义区域：
   134	/// `` `literal text` `` → 内部自动 regex::escape（纯文本匹配）
   135	/// `\`` 在反引号区域内表示字面反引号
   136	/// 反引号外的部分保持原样（正则表达式）
   137	///
   138	/// 示例：
   139	/// `` `fn main()`*\n `` → 匹配 "fn main()" 后跟正则 `*\n`
   140	/// `` `def reg():` `` → 匹配字面 "def reg():"
   141	pub fn expand_pattern(pattern: &str) -> String {
   142	    let mut result = String::new();
   143	    let mut chars = pattern.chars().peekable();
   144	
   145	    while let Some(c) = chars.next() {
   146	        if c == '`' {
   147	            // 进入纯文本区域：收集到未转义的反引号为止
   148	            let mut literal = String::new();
   149	            loop {
   150	                match chars.next() {
   151	                    None => {
   152	                        // 未闭合的反引号 — 当成字面量处理
   153	                        result.push('`');
   154	                        result.push_str(&literal);
   155	                        break;
   156	                    }
   157	                    Some('`') => {
   158	                        // 纯文本区域结束
   159	                        result.push_str(&regex::escape(&literal));
   160	                        break;
   161	                    }
   162	                    Some('\\') if chars.peek() == Some(&'`') => {
   163	                        // 转义的反引号 \`
   164	                        chars.next();
   165	                        literal.push('`');
   166	                    }
   167	                    Some(c) => {
   168	                        literal.push(c);
   169	                    }
   170	                }
   171	            }
   172	        } else {
   173	            result.push(c);
   174	        }
   175	    }
   176	
   177	    result
   178	}
