    99	    dir: &str,
   100	    re: &Regex,
   101	    replacement: &str,
   102	    changed: &mut Vec<(String, String)>,
   103	) -> Result<()> {
   104	    for entry in fs::read_dir(dir).context("读取目录失败")? {
   105	        let entry = entry?;
   106	        let path = entry.path();
   107	        if path.is_dir() {
