    37	                    "description": "目标行号。不指定 line 且匹配唯一时自动选择；不指定 line 且匹配不唯一时报错。"
    38	                }
    39	            },
    40	            "required": ["file", "pattern", "replacement"],
    41	            "additionalProperties": false
    42	        }),
    43	        handler: Box::new(|args| Box::pin(execute(args))),
    44	    }
    45	}
