   110	    let fname = std::path::Path::new(path)
   111	        .file_name()
   112	        .and_then(|n| n.to_str())
   113	        .unwrap_or("");
   114	    fname.eq_ignore_ascii_case("makefile")
   115	        || fname.eq_ignore_ascii_case("gnumakefile")
   116	        || fname.eq_ignore_ascii_case("dockerfile")
   117	        || fname.ends_with(".mk")
   118	}
   119	
   120	/// \r\n → \n，行首连续 tab → 4 空格
   121	pub fn normalize(s: &str) -> String {
   122	    let s = s.replace("\r\n", "\n");
   123	    s.split('\n')
   124	        .map(|line| {
   125	            let tabs = line.len() - line.trim_start_matches('\t').len(); // 行首 tab 字节数
   126	            let rest = &line[tabs..];
   127	            format!("{}{}", "    ".repeat(tabs), rest)
   128	        })
   129	        .collect::<Vec<_>>()
   130	        .join("\n")
   131	}
