   180	/// 编码鲁棒的文件读取函数。
   181	///
   182	/// 优先尝试 UTF-8（快速路径），失败后依次尝试…
   183	[截断：文件较大 (~3376 tok)，仅显示开头 1500 tok + 结尾 500 tok]
   184	… return (content[..end].to_owned(), true);
   185	        }
   186	    }
   187	    // 回退：字节估算
   188	    let max_bytes = max_tok * 4;
   189	    if content.len() <= max_bytes {
   190	        return (content.to_owned(), false);
   191	    }
   192	    let end = content.floor_char_boundary(max_bytes.min(content.len()));
   193	    (content[..end].to_owned(), true)
   194	}
