    51	async fn execute(args: Value, read_tracker: Arc<Mutex<HashSet<String>>>) -> Result<ToolOutcome> {
    52	    let path = args["path"].as_str().context("缺少 path 参数")?;
    53	
    54	    if !std::path::Path::new(path).exists() {
    55	        anyhow::bail!("文件不存在: {}", path);
    56	    }
    57	
    58	    let original = read_file_robust(path)?;
    59	    let is_mk = is_tabsensitive(path);
    60	    let content = if is_mk { original } else { normalize(&original) };
    61	    let warning = if is_mk { format!("\n{}", TABSENSITIVE_WARNING) } else { String::new() };
    62	
    63	    if content.is_empty() {
    64	        return Ok(ToolOutcome {
    65	            summary: format!("[空文件] {}{}", path, warning),
    66	            inverse: None,
    67	
    68	        rollback: false,
    69	
    70	        approval_pending: None,
    71	            inject_messages: vec![],
    72	            defer_rollback: false,
    73	        });
    74	    }
    75	
    76	    // 自动截断：仅当 all=false 且未指定显式行范围时才生效
    77	    let all = args.get("all").and_then(Value::as_bool).unwrap_or(false);
    78	    let has_explicit_range = args.get("start_line").is_some() || args.get("end_line").is_some();
    79	    let display_content = if !all && !has_explicit_range {
    80	        let (truncated, _) = auto_truncate(&content, 2000, 1500, 500);
    81	        truncated
    82	    } else {
    83	        content.clone()
    84	    };
    85	
    86	    let total = content.lines().count();
    87	    let lines: Vec<&str> = display_content.lines().collect();
    88	    let display_total = lines.len();
    89	
    90	    let start = args["start_line"].as_u64().unwrap_or(1) as usize;
    91	    let end = args["end_line"].as_u64().map(|e| e as usize).unwrap_or(display_total);
    92	
    93	    let start = start.max(1).min(display_total);
    94	    let end = end.max(start).min(display_total);
    95	
    96	    let selected: Vec<String> = lines[start - 1..end]
    97	        .iter()
    98	        .enumerate()
    99	        .map(|(i, line)| format!("{:>6}\t{}", start + i, line))
   100	        .collect();
   101	
   102	    let summary = format!(
   103	        "[FILE] {} (共 {} 行, 显示 {}–{})\n{}{}",
   104	        path,
   105	        total,
   106	        start,
   107	        end,
   108	        selected.join("\n"),
   109	        warning,
   110	    );
   111	
   112	    // 注册已读文件（写前检查用）
   113	    let mut tracker = read_tracker.lock().await;
   114	    if let Ok(abs) = std::path::absolute(path) {
   115	        tracker.insert(abs.to_string_lossy().replace('\\', "/"));
   116	    } else {
   117	        tracker.insert(path.to_string());
   118	    }
   119	    drop(tracker);
   120	
   121	    Ok(ToolOutcome {
   122	        summary,
   123	        inverse: None,
   124	
   125	        rollback: false,
   126	
   127	        approval_pending: None,
   128	        inject_messages: vec![],
   129	            defer_rollback: false,
   130	        })
   131	}

