    17	        schema: serde_json::json!({
    18	            "type": "object",
    19	            "properties": {
    20	                "path": {
    21	                    "type": "string",
    22	                    "description": "目标文件或目录的绝对路径"
    23	                },
    24	                "pattern": {
    25	                    "type": "string",
    26	                    "description": "正则表达式；反引号内纯文本，可混写。如 `fn()`abc"
    27	                },
    28	                "replacement": {
    29	                    "type": "string",
    30	                    "description": "要替换为的字符串"
    31	                }
    32	            },
    33	            "required": ["path", "pattern", "replacement"],
    34	            "additionalProperties": false
    35	        }),
    36	        handler: Box::new(|args| Box::pin(execute(args))),
