    40	async fn execute(args: Value) -> Result<ToolOutcome> {
    41	    let path = args["path"].as_str().context("缺少 path 参数")?;
    42	    let raw_pattern = args["pattern"].as_str().context("缺少 pattern 参数")?;
    43	    let replacement = args["replacement"].as_str().context("缺少 replacement 参数")?;
    44	
    45	    let re_pattern = expand_pattern(raw_pattern);
    46	    let re = Regex::new(&re_pattern).context("正则表达式无效")?;
    47	    let meta = fs::metadata(path).context("路径不存在")?;
    48	
    49	    let mut changed_files: Vec<(String, String)> = Vec::new();
    50	
    51	    if meta.is_dir() {
    52	        replace_in_dir(path, &re, replacement, &mut changed_files)?;
    53	    } else {
    54	        replace_in_file(path, &re, replacement, &mut changed_files)?;
    55	    }
    56	
    57	    if changed_files.is_empty() {
    58	        return Ok(ToolOutcome {
    59	            summary: "replace: 无匹配".into(),
    60	            inverse: None,
    61	        
    62	        rollback: false,
    63	        
    64	        approval_pending: None,
    65	            inject_messages: vec![],
    66	            defer_rollback: false,
    67	        });
    68	    }
    69	
    70	    let file_list: Vec<String> = changed_files
    71	        .iter()
    72	        .map(|(p, _)| p.clone())
