    98	fn replace_in_dir(
    99	    dir: &str,
   100	    re: &Regex,
   101	    replacement: &str,
   102	    changed: &mut Vec<(String, String)>,
   103	) -> Result<()> {
   104	    for entry in fs::read_dir(dir).context("读取目录失败")? {
   105	        let entry = entry?;
   106	        let path = entry.path();
   107	        if path.is_dir() {
   108	            let name = entry.file_name().to_string_lossy().to_string();
   109	            if !name.starts_with('.') && name != "node_modules" && name != "target" {
   110	                replace_in_dir(&path.to_string_lossy(), re, replacement, changed)?;
   111	            }
   112	        } else if is_text_file(&path) {
   113	            replace_in_file(&path.to_string_lossy(), re, replacement, changed)?;
   114	        }
   115	    }
   116	    Ok(())
   117	}
   118	
   119	fn replace_in_file(
   120	    path: &str,
   121	    re: &Regex,
   122	    replacement: &str,
   123	    changed: &mut Vec<(String, String)>,
   124	) -> Result<()> {
   125	    let original = match read_file_robust(path) {
   126	        Ok(c) => c,
   127	        Err(_) => return Ok(()),
   128	    };
   129	
   130	    let content = normalize(&original);
   131	    let new = replace_all(re, &content, replacement)?;
   132	    if new != content {
   133	        fs::write(path, &new).context("写入文件失败")?;
   134	        changed.push((path.to_string(), original));
   135	    }
   136	    Ok(())
   137	}
   138	
   139	/// 全文替换所有匹配（fancy_regex 不自带 replace_all）
   140	fn replace_all(re: &Regex, content: &str, replacement: &str) -> Result<String> {
   141	    let mut result = String::new();
   142	    let mut last_end = 0;
   143	    for m in re.find_iter(content) {
   144	        let m = m.context("正则匹配错误")?;
   145	        result.push_str(&content[last_end..m.start()]);
   146	        result.push_str(replacement);
   147	        last_end = m.end();
   148	    }
   149	    result.push_str(&content[last_end..]);
   150	    Ok(result)
   151	}
   152	
   153	fn is_text_file(path: &std::path::Path) -> bool {
   154	    match path.extension().and_then(|e| e.to_str()) {
   155	        Some(ext) => matches!(
   156	            ext,
   157	            "rs"
   158	                | "py"
   159	                | "js"
   160	                | "ts"
   161	                | "jsx"
   162	                | "tsx"
   163	                | "go"
   164	                | "java"
   165	                | "c"
   166	                | "h"
   167	                | "cpp"
   168	                | "hpp"
   169	                | "css"
