   108	/// 文件名是否属于 tab 敏感类型（Makefile recipe、Dockerfile heredoc 等依赖行首 tab）
   109	pub fn is_tabsensitive(path: &str) -> bool {
   110	    let fname = std::path::Path::new(path)
   111	        .file_name()
